import pymysql
import functions_framework
from urllib.parse import unquote

@functions_framework.http
def search_api(request):
    # Establish database connection
    connection = pymysql.connect(
        host='your-cloud-sql-host',
        user='your-username',
        password='your-password',
        database='your-database',
        charset='utf8mb4'
    )
    
    try:
        with connection.cursor() as cursor:
            # Build dynamic WHERE clause from request parameters
            where_conditions = []
            params = {}
            
            # Handle various search parameters
            for key, value in request.args.items():
                if value and key != 'limit':
                    if key in ['name', 'email', 'category']:
                        where_conditions.append(f"{key} LIKE %s")
                        params[key] = f"%{value}%"
                    elif key in ['min_age', 'max_age']:
                        where_conditions.append(f"age {('=' if key == 'age' else ('>=' if key == 'min_age' else '<='))} %s")
                        params[key] = value
                    elif key == 'status':
                        where_conditions.append("status = %s")
                        params[key] = value
            
            # Construct base query
            base_query = "SELECT * FROM users"
            if where_conditions:
                base_query += " WHERE " + " AND ".join(where_conditions)
            
            # Add ORDER BY and LIMIT
            base_query += " ORDER BY created_at DESC"
            
            if 'limit' in request.args:
                base_query += " LIMIT %s"
                params['limit'] = int(request.args['limit'])
            else:
                base_query += " LIMIT 100"
            
            # Execute query
            cursor.execute(base_query, tuple(params.values()))
            results = cursor.fetchall()
            
            # Format results
            columns = [desc[0] for desc in cursor.description]
            formatted_results = [dict(zip(columns, row)) for row in results]
            
            return {
                'status': 'success',
                'data': formatted_results,
                'count': len(formatted_results)
            }
            
    except Exception as e:
        return {
            'status': 'error',
            'message': str(e)
        }
    finally:
        connection.close()